// One post per day, queue not burst. Checks a queue counter before
// proceeding -- if already posted today, this project's carousel waits.
const fs = require('fs');
const path = require('path');
let queue = [];
try { queue = JSON.parse(fs.readFileSync(path.join('Shared', 'linkedin_queue.json'), 'utf8')); } catch (e) {}
const today = new Date().toISOString().slice(0, 10);
const postedToday = queue.some(q => q.posted_date === today);
return [{ json: { ...$json, can_post_today: !postedToday } }];

// Fixed branded slide template, pdf-lib, no browser, no native deps.
const { PDFDocument, rgb } = require('pdf-lib');
const fs = require('fs');
const path = require('path');

const templateBytes = fs.readFileSync(path.join('Originals', 'brand_shell', 'carousel_template.pdf'));
const pdfDoc = await PDFDocument.load(templateBytes);

const slides = JSON.parse($json.response || '[]');
const pages = pdfDoc.getPages();
slides.slice(0, pages.length).forEach((text, i) => {
  pages[i].drawText(String(text).slice(0, 500), { x: 50, y: 400, size: 14, color: rgb(0.05, 0.13, 0.28) });
});

const outPath = path.join('Working', $json.project_prefix, 'carousel_output.pdf');
const bytes = await pdfDoc.save();
fs.writeFileSync(outPath, bytes);

return [{ json: { ...$json, pdf_path: outPath } }];

// Public-post scan: zero client names, contact hashes, unfilled placeholders.
const fs = require('fs');
const text = JSON.stringify($json);
const hasPlaceholder = /{{.*?}}/.test(text);
let contacts = [];
try { contacts = JSON.parse(fs.readFileSync(require('path').join('Working', $json.project_prefix, 'contacts.json'), 'utf8')); } catch (e) {}
const leaksContactData = contacts.some(c => text.includes(c.email) || (c.organization && text.includes(c.organization)));
return [{ json: { ...$json, scan_passed: !hasPlaceholder && !leaksContactData } }];

// LinkedIn's real multi-step document upload flow: register, transmit,
// finalize -- never a single inline request assuming it fits one call.
const fs = require('fs');
const token = fs.readFileSync(require('path').join('Shared', 'linkedin_token.txt'), 'utf8').trim();

// Step 1: register the upload
const registerResp = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.linkedin.com/rest/documents?action=initializeUpload',
  headers: { Authorization: 'Bearer ' + token },
  body: { initializeUploadRequest: { owner: 'urn:li:organization:CIRCLEOFCARE' } },
  json: true
});

// Step 2: transmit the asset bytes to the returned upload URL
const fileBytes = fs.readFileSync($json.pdf_path);
await this.helpers.httpRequest({ method: 'PUT', url: registerResp.value.uploadUrl, body: fileBytes });

// Step 3: finalize -- reference the confirmed document URN in the post
const postResp = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.linkedin.com/rest/posts',
  headers: { Authorization: 'Bearer ' + token },
  body: { author: 'urn:li:organization:CIRCLEOFCARE', commentary: $json.caption || '', content: { media: { id: registerResp.value.document } } },
  json: true
});

return [{ json: { ...$json, posted: true, post_urn: postResp.id } }];

// Fallback: PDF + ready caption queued on the dashboard for a one-click manual attach.
const fs = require('fs');
const path = require('path');
let queue = [];
const qPath = path.join('Shared', 'linkedin_queue.json');
try { queue = JSON.parse(fs.readFileSync(qPath, 'utf8')); } catch (e) {}
queue.push({ project_prefix: $json.project_prefix, pdf_path: $json.pdf_path, caption: $json.caption || '', queued_at: new Date().toISOString(), posted_date: null, status: 'awaiting_manual_post' });
fs.writeFileSync(qPath, JSON.stringify(queue, null, 2), 'utf8');
return [{ json: $json }];
